/**
 * Generates OTA_BOOTSTRAP.md — native integration checklist + copy-paste snippets.
 * Used by `npx react-native-nitro-update setup` and `npx react-native-nitro-update bootstrap`.
 */

const fs = require('fs')
const path = require('path')

const EXAMPLE_IOS =
  'https://github.com/fullsnack-DEV/react-native-nitro-update/blob/main/example/ios/NitroUpdateExample/AppDelegate.swift'
const EXAMPLE_ANDROID =
  'https://github.com/fullsnack-DEV/react-native-nitro-update/blob/main/example/android/app/src/main/java/com/nitroupdateexample/MainApplication.kt'

/**
 * @param {object} options
 * @param {string} [options.baseUrl]
 * @param {string} [options.sourceTag]
 * @returns {string}
 */
function getOtaBootstrapMarkdown(options = {}) {
  const baseUrl = (options.baseUrl || 'https://your-cdn.com/ota').replace(/\/$/, '')
  const sourceTag = options.sourceTag || 'npx react-native-nitro-update bootstrap'

  return `# OTA native bootstrap

Generated by: **${sourceTag}**

Use this checklist alongside **\`INTEGRATION.md\`** in \`node_modules/react-native-nitro-update/\` (or the package on npm).

## 1. Dependencies

\`\`\`bash
npm install react-native-nitro-update react-native-nitro-modules
\`\`\`

\`react-native-nitro-modules\` is a **required peer** — npm does not install it automatically when you only add \`react-native-nitro-update\`.

## 2. iOS — Podfile

Inside your app target (path is from \`ios/\`):

\`\`\`ruby
pod 'NitroUpdateBundleManager', :path => '../node_modules/react-native-nitro-update'
\`\`\`

In \`post_install\`:

\`\`\`ruby
require_relative '../node_modules/react-native-nitro-update/scripts/nitro_update_pod_utils'

post_install do |installer|
  # ... your existing post_install (e.g. react_native_post_install) ...
  NitroUpdatePodUtils.apply!(installer)
end
\`\`\`

Then: \`cd ios && pod install && cd ..\`

## 3. iOS — bundle URL (release)

Prefer the canonical **Swift delegate** pattern from the library example:

- **Reference:** [example AppDelegate.swift](${EXAMPLE_IOS})

Summary: in release, \`bundleURL()\` (or \`sourceURL\`) should return \`NitroUpdateBundleManager.getStoredBundleURL()\` before falling back to the embedded \`main.jsbundle\`. In DEBUG, keep Metro.

## 4. Android — JS bundle path (RN 0.76+)

With \`getDefaultReactHost\`, pass the OTA path:

- **Reference:** [example MainApplication.kt](${EXAMPLE_ANDROID})

\`\`\`kotlin
import com.facebook.react.defaults.DefaultReactHost.getDefaultReactHost
import com.margelo.nitro.nitroupdate.NitroUpdateBundleLoader

override val reactHost: ReactHost by lazy {
  getDefaultReactHost(
    context = applicationContext,
    packageList = PackageList(this).packages,
    jsBundleFilePath = NitroUpdateBundleLoader.getStoredBundlePath(this),
  )
}
\`\`\`

Older \`ReactNativeHost\` templates: override \`getJSBundleFile()\` to return \`getStoredBundlePath(this)\` when non-null in release.

## 5. JavaScript

After launch, run \`checkForUpdate\` / \`downloadUpdate\` (and \`confirmBundle()\` when healthy). See **INTEGRATION.md** §4.

Suggested hosted URLs for this app (adjust as needed):

- Version: \`${baseUrl}/version.txt\`
- Zip: \`${baseUrl}/bundle.zip\`

## 6. Verify

\`\`\`bash
npx react-native-nitro-update doctor
npx react-native-nitro-update doctor --json   # CI
\`\`\`

## Expo

Custom native code is required (same iOS/Android steps after prebuild). For fully managed Expo without native edits, use **EAS Update** instead of this library.
`
}

/**
 * @param {string} appDir
 * @param {object} [options]
 * @param {string} [options.baseUrl]
 * @param {string} [options.sourceTag]
 * @param {boolean} [options.quiet]
 */
function writeOtaBootstrap(appDir, options = {}) {
  const outPath = path.join(appDir, 'OTA_BOOTSTRAP.md')
  const md = getOtaBootstrapMarkdown({
    baseUrl: options.baseUrl,
    sourceTag: options.sourceTag,
  })
  fs.writeFileSync(outPath, md, 'utf8')
  if (!options.quiet) {
    console.log(`  \x1b[32mCreated\x1b[0m  OTA_BOOTSTRAP.md  \x1b[2m(native checklist + snippets)\x1b[0m`)
  }
  return outPath
}

module.exports = { getOtaBootstrapMarkdown, writeOtaBootstrap }
